package analytics

import (
	"context"
	"testing"
	"time"

	positionsmath "socialpredict/internal/domain/math/positions"
	"socialpredict/models"
	"socialpredict/models/modelstesting"
	"socialpredict/setup"

	"gorm.io/gorm"
)

type analyticsServiceTestConfig struct {
	repoOptions    []RepositoryOption
	serviceOptions []ServiceOption
}

type analyticsServiceTestOption func(*analyticsServiceTestConfig)

type financialSnapshotComputer interface {
	ComputeUserFinancials(context.Context, FinancialSnapshotRequest) (*FinancialSnapshot, error)
}

func withAnalyticsRepositoryOption(opt RepositoryOption) analyticsServiceTestOption {
	return func(cfg *analyticsServiceTestConfig) {
		cfg.repoOptions = append(cfg.repoOptions, opt)
	}
}

func withAnalyticsServiceOption(opt ServiceOption) analyticsServiceTestOption {
	return func(cfg *analyticsServiceTestConfig) {
		cfg.serviceOptions = append(cfg.serviceOptions, opt)
	}
}

func analyticsConfigFromSetup(econ *setup.EconomicConfig) Config {
	return Config{
		MaximumDebtAllowed: econ.Economics.User.MaximumDebtAllowed,
		CreateMarketCost:   econ.Economics.MarketIncentives.CreateMarketCost,
		InitialBetFee:      econ.Economics.Betting.BetFees.InitialBetFee,
	}
}

func newAnalyticsService(t *testing.T, db *gorm.DB, econ *setup.EconomicConfig, opts ...analyticsServiceTestOption) *Service {
	t.Helper()

	cfg := analyticsServiceTestConfig{}
	for _, opt := range opts {
		opt(&cfg)
	}

	wpamCalculator := modelstesting.SeedWPAMFromConfig(econ)
	positionCalculator := positionsmath.NewPositionCalculator(
		positionsmath.WithProbabilityProvider(positionsmath.NewWPAMProbabilityProvider(wpamCalculator)),
	)
	cfg.repoOptions = append(cfg.repoOptions, WithRepositoryPositionCalculator(NewMarketPositionCalculator(positionCalculator)))
	repo := NewGormRepository(db, cfg.repoOptions...)
	cfg.serviceOptions = append(cfg.serviceOptions, WithPositionCalculator(NewMarketPositionCalculator(positionCalculator)))

	return NewService(repo, analyticsConfigFromSetup(econ), cfg.serviceOptions...)
}

func requireFinancialSnapshot(t *testing.T, svc financialSnapshotComputer, user models.User) *FinancialSnapshot {
	t.Helper()

	snapshot, err := svc.ComputeUserFinancials(context.Background(), FinancialSnapshotRequest{
		Username:       user.Username,
		AccountBalance: user.AccountBalance,
	})
	if err != nil {
		t.Fatalf("ComputeUserFinancials returned error: %v", err)
	}

	return snapshot
}

func TestComputeUserFinancials_NewUser_NoPositions(t *testing.T) {
	db := modelstesting.NewFakeDB(t)
	user := modelstesting.GenerateUser("testuser", 1000)
	if err := db.Create(&user).Error; err != nil {
		t.Fatalf("create user: %v", err)
	}

	econ := modelstesting.GenerateEconomicConfig()
	svc := newAnalyticsService(t, db, econ)

	snapshot := requireFinancialSnapshot(t, svc, user)

	if snapshot.AccountBalance != 1000 {
		t.Errorf("expected account balance 1000, got %d", snapshot.AccountBalance)
	}
	if snapshot.MaximumDebtAllowed != econ.Economics.User.MaximumDebtAllowed {
		t.Errorf("unexpected max debt: %d", snapshot.MaximumDebtAllowed)
	}
	if snapshot.AmountInPlay != 0 || snapshot.TradingProfits != 0 || snapshot.TotalProfits != 0 {
		t.Errorf("expected zeroed snapshot, got %+v", snapshot)
	}
}

func TestComputeUserFinancials_NegativeBalance(t *testing.T) {
	db := modelstesting.NewFakeDB(t)
	user := modelstesting.GenerateUser("borrower", -50)
	if err := db.Create(&user).Error; err != nil {
		t.Fatalf("create user: %v", err)
	}

	econ := modelstesting.GenerateEconomicConfig()
	svc := newAnalyticsService(t, db, econ)

	snapshot := requireFinancialSnapshot(t, svc, user)

	if snapshot.AmountBorrowed != 50 {
		t.Errorf("expected amountBorrowed 50, got %d", snapshot.AmountBorrowed)
	}
	expectedEquity := int64(-100)
	if snapshot.Equity != expectedEquity {
		t.Errorf("expected equity %d, got %d", expectedEquity, snapshot.Equity)
	}
}

func TestComputeUserFinancials_WithActivePositions(t *testing.T) {
	db := modelstesting.NewFakeDB(t)
	user := modelstesting.GenerateUser("trader", 500)
	if err := db.Create(&user).Error; err != nil {
		t.Fatalf("create user: %v", err)
	}

	market := modelstesting.GenerateMarket(1, user.Username)
	market.IsResolved = false
	if err := db.Create(&market).Error; err != nil {
		t.Fatalf("create market: %v", err)
	}

	bets := []models.Bet{
		modelstesting.GenerateBet(100, "YES", user.Username, uint(market.ID), 0),
		modelstesting.GenerateBet(50, "NO", user.Username, uint(market.ID), time.Minute),
	}
	for _, bet := range bets {
		if err := db.Create(&bet).Error; err != nil {
			t.Fatalf("create bet: %v", err)
		}
	}

	econ := modelstesting.GenerateEconomicConfig()
	svc := newAnalyticsService(t, db, econ)

	snapshot := requireFinancialSnapshot(t, svc, user)

	if snapshot.AmountInPlay == 0 {
		t.Errorf("expected non-zero amount in play, got %d", snapshot.AmountInPlay)
	}
	if snapshot.AmountInPlayActive == 0 {
		t.Errorf("expected active amount in play, got %d", snapshot.AmountInPlayActive)
	}
	if snapshot.TotalSpent == 0 {
		t.Errorf("expected total spent > 0")
	}
}
package analytics

import (
	"context"
	"errors"
)

// ComputeUserFinancials calculates comprehensive financial metrics for a user.
func (s *Service) ComputeUserFinancials(ctx context.Context, req FinancialSnapshotRequest) (*FinancialSnapshot, error) {
	if req.Username == "" {
		return nil, errors.New("username is required")
	}

	if s.repo == nil {
		return nil, errors.New("repository not provided")
	}

	positions, err := s.repo.UserMarketPositions(ctx, req.Username)
	if err != nil {
		return nil, err
	}

	snapshot := &FinancialSnapshot{
		AccountBalance:     req.AccountBalance,
		MaximumDebtAllowed: s.config.MaximumDebtAllowed,
	}

	for _, pos := range positions {
		profit := pos.Value - pos.TotalSpent

		snapshot.AmountInPlay += pos.Value
		snapshot.TotalSpent += pos.TotalSpent
		snapshot.TradingProfits += profit

		if pos.IsResolved {
			snapshot.RealizedProfits += profit
			snapshot.RealizedValue += pos.Value
		} else {
			snapshot.PotentialProfits += profit
			snapshot.PotentialValue += pos.Value
			snapshot.AmountInPlayActive += pos.Value
			snapshot.TotalSpentInPlay += pos.TotalSpentInPlay
		}
	}

	if req.AccountBalance < 0 {
		snapshot.AmountBorrowed = -req.AccountBalance
	}

	snapshot.RetainedEarnings = req.AccountBalance - snapshot.AmountInPlay
	snapshot.Equity = snapshot.RetainedEarnings + snapshot.AmountInPlay - snapshot.AmountBorrowed
	snapshot.TotalProfits = snapshot.TradingProfits + snapshot.WorkProfits

	return snapshot, nil
}
package analytics

import (
	"context"

	"socialpredict/internal/domain/boundary"
	positionsmath "socialpredict/internal/domain/math/positions"
)

// DebtRepository exposes only the user data needed for debt calculations.
type DebtRepository interface {
	ListUsers(ctx context.Context) ([]UserAccount, error)
}

// VolumeRepository exposes the market and bet data needed for volume calculations.
type VolumeRepository interface {
	ListMarkets(ctx context.Context) ([]MarketRecord, error)
	ListBetsForMarket(ctx context.Context, marketID uint) ([]boundary.Bet, error)
}

// FeeRepository exposes the ordered bet data needed for participation fee calculations.
type FeeRepository interface {
	ListBetsOrdered(ctx context.Context) ([]boundary.Bet, error)
}

// LeaderboardRepository provides the data required to compute leaderboards.
type LeaderboardRepository interface {
	DebtRepository
	VolumeRepository
}

// FinancialsRepository provides the data required for per-user financial snapshots.
type FinancialsRepository interface {
	UserMarketPositions(ctx context.Context, username string) ([]positionsmath.MarketPosition, error)
}

// StatsRepository exposes aggregate account data required by stats reporting.
type StatsRepository interface {
	CountUsersByType(ctx context.Context, userType string) (int64, error)
}

// Config captures the accounting-relevant policy slice required by analytics.
// It is a process-start snapshot; historically exact fee or cost reporting across
// future economics rollouts still requires durable per-market or per-bet policy capture.
type Config struct {
	MaximumDebtAllowed int64
	CreateMarketCost   int64
	InitialBetFee      int64
}

// DebtCalculator calculates debt-related metrics.
type DebtCalculator interface {
	Calculate(ctx context.Context, repo DebtRepository, config Config) (*DebtStats, error)
}

// VolumeCalculator calculates market volume metrics.
type VolumeCalculator interface {
	Calculate(ctx context.Context, repo VolumeRepository, config Config) (*MarketVolumeStats, error)
}

// FeeCalculator calculates betting fee metrics.
type FeeCalculator interface {
	CalculateParticipationFees(ctx context.Context, repo FeeRepository, config Config) (int64, error)
}

// MetricsAssembler combines calculator outputs into the final DTO.
type MetricsAssembler interface {
	Assemble(debt *DebtStats, volume *MarketVolumeStats, participationFees int64) *SystemMetrics
}

// MarketPositionCalculator calculates market positions for analytics consumers.
type MarketPositionCalculator interface {
	Calculate(snapshot positionsmath.MarketSnapshot, bets []boundary.Bet) ([]positionsmath.MarketPosition, error)
}

// Repository exposes the data access required by the analytics domain service.
type Repository interface {
	LeaderboardRepository
	FeeRepository
	FinancialsRepository
	StatsRepository
}

// Service implements analytics calculations.
type Service struct {
	repo             Repository
	debtRepo         DebtRepository
	volumeRepo       VolumeRepository
	feeRepo          FeeRepository
	leaderboardRepo  LeaderboardRepository
	financialsRepo   FinancialsRepository
	statsRepo        StatsRepository
	config           Config
	debtCalculator   DebtCalculator
	volumeCalculator VolumeCalculator
	feeCalculator    FeeCalculator
	metricsAssembler MetricsAssembler
	positions        MarketPositionCalculator
}

// ServiceOption allows customizing analytics strategies.
type ServiceOption func(*Service)

func defaultDebtCalculator() DebtCalculator {
	return DefaultDebtCalculator{}
}

func defaultVolumeCalculator() VolumeCalculator {
	return DefaultVolumeCalculator{}
}

func defaultFeeCalculator() FeeCalculator {
	return DefaultFeeCalculator{}
}

func defaultMetricsAssembler() MetricsAssembler {
	return DefaultMetricsAssembler{}
}

func defaultPositionCalculator() MarketPositionCalculator {
	return defaultMarketPositionCalculator{}
}

func debtCalculatorOrDefault(calculator DebtCalculator) DebtCalculator {
	if calculator == nil {
		return defaultDebtCalculator()
	}
	return calculator
}

func volumeCalculatorOrDefault(calculator VolumeCalculator) VolumeCalculator {
	if calculator == nil {
		return defaultVolumeCalculator()
	}
	return calculator
}

func feeCalculatorOrDefault(calculator FeeCalculator) FeeCalculator {
	if calculator == nil {
		return defaultFeeCalculator()
	}
	return calculator
}

func metricsAssemblerOrDefault(assembler MetricsAssembler) MetricsAssembler {
	if assembler == nil {
		return defaultMetricsAssembler()
	}
	return assembler
}

func positionCalculatorOrDefaultStrategy(calculator MarketPositionCalculator) MarketPositionCalculator {
	if calculator == nil {
		return defaultPositionCalculator()
	}
	return calculator
}

func (s *Service) setRepository(repo Repository) {
	if s == nil {
		return
	}
	s.repo = repo
	s.debtRepo = repo
	s.volumeRepo = repo
	s.feeRepo = repo
	s.leaderboardRepo = repo
	s.financialsRepo = repo
	s.statsRepo = repo
}

// WithDebtCalculator overrides the default debt calculator.
func WithDebtCalculator(c DebtCalculator) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.debtCalculator = debtCalculatorOrDefault(c)
		}
	}
}

// WithVolumeCalculator overrides the default volume calculator.
func WithVolumeCalculator(c VolumeCalculator) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.volumeCalculator = volumeCalculatorOrDefault(c)
		}
	}
}

// WithFeeCalculator overrides the default fee calculator.
func WithFeeCalculator(c FeeCalculator) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.feeCalculator = feeCalculatorOrDefault(c)
		}
	}
}

// WithMetricsAssembler overrides the default metrics assembler.
func WithMetricsAssembler(a MetricsAssembler) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.metricsAssembler = metricsAssemblerOrDefault(a)
		}
	}
}

// WithPositionCalculator overrides the default position calculator.
func WithPositionCalculator(c MarketPositionCalculator) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.positions = positionCalculatorOrDefaultStrategy(c)
		}
	}
}

