		return nil, err
	}

package bets

import (
	"context"

	dusers "socialpredict/internal/domain/users"
)

// Place creates a buy bet after validating market status and user balance.
// Placement mutates balances and bet history synchronously inside one transaction.
func (s *Service) Place(ctx context.Context, req PlaceRequest) (*PlacedBet, error) {
	outcome, err := s.placeValidator.Validate(ctx, req)
	if err != nil {
		return nil, err
	}
	if outcome == "" {
		return nil, ErrInvalidOutcome
	}

	if _, err := s.marketGate.Open(ctx, int64(req.MarketID)); err != nil {
		return nil, err
	}

	if s.placeUnit == nil {
		return nil, ErrPlaceTransactionUnavailable
	}

	return s.placeInTransaction(ctx, req, outcome)

package markets

import (
	"context"
)

// ResolveMarket resolves a market with a given outcome.
// Resolution updates market state and user balances synchronously.
func (s *Service) ResolveMarket(ctx context.Context, marketID int64, resolution string, username string) error {
	outcome, err := s.resolutionPolicy.NormalizeResolution(resolution)
	if err != nil {
		return err
	}

	market, err := s.repo.GetByID(ctx, marketID)
	if err != nil {
		return ErrMarketNotFound
	}
	if market == nil {
		return ErrMarketNotFound
	}

	if err := s.resolutionPolicy.ValidateResolutionRequest(market, username); err != nil {
		return err
	}

	return s.resolutionPolicy.Resolve(ctx, s.repo, s.userService, marketID, outcome)
}

